def frequencia_palavras(texto: str) -> dict:
    """Retorna um dicionário com a frequência de cada palavra na string."""
    frequencia = {}
    palavras = texto.split()
    for palavra in palavras:
        palavra = palavra.lower()
        if palavra in frequencia:
            frequencia[palavra] = frequencia[palavra] + 1
        else:
            frequencia[palavra] = 1
    return frequencia

def fatorial(n):
    """Retorna o fatorial de n recursivamente."""
    if n == 0:
        return 1
    return n * fatorial(n - 1)
